mapper.select:
select instance_id as instanceId, instance_no as instanceNo, title, run_state as runState, result_state as resultState, start_employee_name_snapshot as startEmployeeNameSnapshot, started_at as startedAt, finished_at as finishedAt from t_bpm_instance where 1 = 1
and instance_no like concat('%', #{queryForm.instanceNo}, '%')
and title like concat('%', #{queryForm.title}, '%')
and run_state = #{queryForm.runState}
and start_employee_id = #{queryForm.startEmployeeId}
order by started_at desc, instance_id desc
